"use strict";

const {
  test,
  expect
} = require('@playwright/test');
test.describe('UsedCarMart E2E', () => {
  test('buyer and seller critical journeys', async ({
    page
  }) => {
    const base = 'http://127.0.0.1:8080';
    await page.goto(base + '/login.html');
    await page.fill('#userId', 'demoBuyer');
    await page.fill('#password', 'Demo@1234');
    await page.click('button[type="submit"]');
    await expect(page).toHaveURL(/buyer-home\.html/);
    await expect(page.locator('.car-card').first()).toBeVisible();
    await page.selectOption('#fuel-filter', 'Petrol');
    await expect(page.locator('#result-count')).toContainText('result');
    await page.locator('button:has-text("View Details")').first().click();
    await expect(page).toHaveURL(/car-details\.html/);
    const wishlistBtn = page.locator('#wishlist-btn');
    const beforeText = (await wishlistBtn.textContent()) || '';
    await wishlistBtn.click();
    const afterText = (await wishlistBtn.textContent()) || '';
    expect(afterText).not.toEqual(beforeText);
    await page.click('a:has-text("Wishlist")');
    await expect(page).toHaveURL(/wishlist\.html/);
    await expect(page.locator('.wishlist-card').first()).toBeVisible();
    await page.click('a:has-text("Recent")');
    await expect(page).toHaveURL(/recently-viewed\.html/);
    await expect(page.locator('a:has-text("View Again")').first()).toBeVisible();
    await page.goto(base + '/purchase.html?id=CAR_TEST');
    await expect(page.locator('body')).toContainText(/404|File not found|Error code/i);
    await page.goto(base + '/login-seller.html');
    await page.fill('#userId', 'demoSeller');
    await page.fill('#password', 'Demo@1234');
    await page.click('#submit-btn');
    await expect(page).toHaveURL(/seller-dashboard\.html/);
    const beforeListed = Number((await page.locator('#m-listed').textContent()) || 0);
    expect(beforeListed).toBeGreaterThan(0);
    await page.click('a:has-text("+ Add Car")');
    await expect(page).toHaveURL(/add-car\.html/);
    await page.selectOption('#make', 'Maruti Suzuki');
    await page.fill('#model', 'Baleno QA');
    await page.selectOption('#year', {
      label: '2022'
    });
    await page.selectOption('#color', 'Blue');
    await page.check('input[name="fuelType"][value="Petrol"]');
    await page.check('input[name="transmission"][value="Manual"]');
    await page.fill('#mileage', '28000');
    await page.fill('#price', '620000');
    await page.click('button[type="submit"]');
    await expect(page.locator('#success-alert')).toHaveClass(/visible/);
    await expect(page).toHaveURL(/seller-dashboard\.html/, {
      timeout: 10000
    });
    const afterListed = Number((await page.locator('#m-listed').textContent()) || 0);
    expect(afterListed).toBeGreaterThanOrEqual(beforeListed + 1);
  });
});
